INSERT INTO book (id, title, author, isbn, category_id, price, stock, publisher, publish_date, description, cover_url, status, created_at, updated_at, is_deleted) VALUES

-- ====================
-- 文学小说 (category_id = 1, 12本)
-- ====================
(1,  '活着',            '余华',      '9787530215319', 1, 35.00,  200, '北京十月文艺出版社', '2012-08-01', '《活着》讲述了农村人福贵悲惨的人生遭遇。福贵本是个阔少爷，因嗜赌如命败光了家产。此后他的人生被历史的车轮不断碾压，亲人相继离世，最后只剩下一头老牛和他相依为命。这是一部充满血泪的小说，展现了生命的脆弱与坚韧。', '', 1, NOW(), NOW(), 0),
(2,  '百年孤独',        '加西亚·马尔克斯', '9787544253994', 1, 55.00,  150, '南海出版公司',       '2011-06-01', '《百年孤独》是魔幻现实主义文学的代表作，描写了布恩迪亚家族七代人的传奇故事，以及加勒比海沿岸小镇马孔多的百年兴衰。作品融入神话传说、民间故事、宗教典故等因素，巧妙地糅合了现实与虚幻，展现出一个瑰丽的想象世界。', '', 1, NOW(), NOW(), 0),
(3,  '围城',            '钱钟书',    '9787020024759', 1, 28.00,  180, '人民文学出版社',     '1991-02-01', '《围城》是中国现代文学史上一部风格独特的讽刺小说。钱钟书以幽默机智的笔触，讲述了主人公方鸿渐在欧洲留学归来后的人生遭遇，对知识分子的虚荣、软弱和婚姻困境进行了深刻剖析。"围城"已成为人们形容婚姻困境的经典比喻。', '', 1, NOW(), NOW(), 0),
(4,  '三体',            '刘慈欣',    '9787536692930', 1, 62.00,  300, '重庆出版社',         '2008-01-01', '《三体》是刘慈欣创作的系列长篇科幻小说，讲述了地球人类文明和三体文明的信息交流、生死搏杀及两个文明在宇宙中的兴衰历程。作品格局宏大，想象力惊人，被誉为中国科幻文学的里程碑之作，荣获第73届雨果奖最佳长篇小说奖。', '', 1, NOW(), NOW(), 0),
(5,  '红楼梦',          '曹雪芹',    '9787020002207', 1, 59.70,  120, '人民文学出版社',     '1996-12-01', '《红楼梦》是中国古典四大名著之首，以贾宝玉、林黛玉和薛宝钗的爱情悲剧为主线，通过贾史王薛四大家族的兴衰，广阔而真实地展示了中国封建社会末期的生活画卷。全书人物刻画栩栩如生，描写细腻入微，是中国文学的巅峰之作。', '', 1, NOW(), NOW(), 0),
(6,  '平凡的世界',      '路遥',      '9787530212004', 1, 39.80,  250, '北京十月文艺出版社', '2012-03-01', '《平凡的世界》以中国70年代中期到80年代中期十年间为背景，以孙少安和孙少平两兄弟为中心，刻画了当时社会各阶层众多普通人的形象，深刻地展示了普通人在大时代历史进程中所走过的艰难曲折的道路。', '', 1, NOW(), NOW(), 0),
(7,  '挪威的森林',      '村上春树',  '9787532725694', 1, 36.00,  160, '上海译文出版社',     '2007-07-01', '《挪威的森林》是村上春树的代表作。故事讲述主角渡边纠缠在情绪不稳定且患有精神疾病的直子和开朗活泼的绿子之间，展开了自我成长的旅程。这是一部动人心弦的青春恋爱小说，带有浓厚的孤独与迷茫气息。', '', 1, NOW(), NOW(), 0),
(8,  '小王子',          '安托万·德·圣-埃克苏佩里', '9787020042494', 1, 22.00, 200, '人民文学出版社', '2003-08-01', '《小王子》是一则关于爱与责任的寓言。小王子离开自己的星球，在太空中旅行，最后来到地球。他以孩童的眼光看世界，道出了成人世界的荒谬。这本书适合所有年龄段的人阅读，每次重读都能获得新的感悟。', '', 1, NOW(), NOW(), 0),
(9,  '白鹿原',          '陈忠实',    '9787020104550', 1, 48.00,  140, '人民文学出版社',     '2012-09-01', '《白鹿原》以陕西关中平原上的白鹿村为背景，讲述了白鹿两家祖孙三代的恩怨纷争。小说浓缩了从清朝末年到20世纪七八十年代长达半个多世纪的中国农村社会变迁，是一部气势恢宏的民族史诗。', '', 1, NOW(), NOW(), 0),
(10, '追风筝的人',      '卡勒德·胡赛尼', '9787208061644', 1, 29.00, 170, '上海人民出版社',   '2006-05-01', '《追风筝的人》讲述了12岁的阿富汗富家少爷阿米尔与仆人哈桑情同手足的故事。一场风筝比赛后发生的悲惨事件，让阿米尔陷入了深深的自责与痛苦。成年后的阿米尔踏上救赎之路，回到战火纷飞的阿富汗寻找哈桑的儿子。', '', 1, NOW(), NOW(), 0),
(11, '杀死一只知更鸟',  '哈珀·李',  '9787544270878', 1, 42.00,  130, '南海出版公司',       '2012-09-01', '《杀死一只知更鸟》以6岁小女孩斯库特的视角，讲述了20世纪30年代美国南方小镇上的一起种族歧视案件。律师父亲阿蒂克斯为被诬告的黑人辩护，让孩子们从小懂得了正义、勇气和同理心的真正含义。', '', 1, NOW(), NOW(), 0),
(12, '霍乱时期的爱情',  '加西亚·马尔克斯', '9787544253543', 1, 49.00, 110, '南海出版公司',   '2012-09-01', '《霍乱时期的爱情》讲述了一段跨越半个多世纪的爱情史诗。弗洛伦蒂诺·阿里萨在年轻时爱上了费尔明娜·达萨，经历了53年7个月零11天的等待后，两人终于在暮年走到了一起。马尔克斯穷尽了爱情的所有可能性。', '', 1, NOW(), NOW(), 0),

