(13, '深入理解计算机系统', '兰德尔·E·布莱恩特', '9787111544937', 2, 139.00, 80, '机械工业出版社',   '2016-11-01', '本书从程序员的视角出发，系统介绍了计算机系统的各个核心概念，包括数据表示、机器级程序、处理器体系结构、内存层次、链接、异常控制流、虚拟内存和系统级I/O等。是计算机科学领域广受赞誉的经典教材，被誉为"程序员的内功心法"。', '', 1, NOW(), NOW(), 0),
(14, '算法导论',          '托马斯·H·科尔曼', '9787111407010', 2, 128.00, 90, '机械工业出版社',   '2013-01-01', '《算法导论》是全球影响力最大的算法教材，全面介绍了各种算法及其分析。内容涵盖排序、数据结构、图算法、动态规划、贪心算法、多线程算法等。本书既适合教学使用，也是程序员必备的案头参考书。', '', 1, NOW(), NOW(), 0),
(15, 'Java编程思想',      '布鲁斯·埃克尔',   '9787111213826', 2, 108.00, 100, '机械工业出版社',   '2007-06-01', '《Java编程思想》是Java领域的经典之作，全面深入讲解了Java编程的核心概念。从面向对象编程的基本原理到高级特性如泛型、注解、并发编程等，帮助读者建立扎实的Java编程基础。', '', 1, NOW(), NOW(), 0),
(16, 'Python编程：从入门到实践', '埃里克·马瑟斯', '9787115428028', 2, 89.00, 150, '人民邮电出版社', '2016-07-01', '本书是Python入门领域的畅销书，分为基础知识和实际项目两部分。基础部分涵盖变量、列表、字典、类、文件操作等；项目部分带领读者用Python开发游戏、数据可视化和Web应用，真正做到学以致用。', '', 1, NOW(), NOW(), 0),
(17, '高性能MySQL',       '施瓦茨',          '9787121175350', 2, 99.00, 70,  '电子工业出版社',   '2013-05-01', '《高性能MySQL》是MySQL领域的权威著作，全面覆盖MySQL 5.5版本的高级特性。内容包括架构设计、索引优化、查询性能调优、高级复制特性、备份与恢复、安全机制等。是DBA和后端开发人员的必读之书。', '', 1, NOW(), NOW(), 0),
(18, '代码整洁之道',      '罗伯特·C·马丁',  '9787115216878', 2, 59.00, 120, '人民邮电出版社',   '2010-01-01', '软件质量不仅取决于架构和设计，更在于代码的质量。本书提出了代码整洁的系列原则和最佳实践，涵盖命名、函数、注释、格式、错误处理等方方面面。读完本书你会发现，写出整洁的代码是一种责任，也是一种享受。', '', 1, NOW(), NOW(), 0),
(19, '计算机网络：自顶向下方法', '詹姆斯·F·库罗斯', '9787111599716', 2, 89.00, 85, '机械工业出版社', '2018-06-01', '本书以自顶向下的方式讲解计算机网络，从应用层协议开始，逐步深入到传输层、网络层、链路层。书中穿插了大量真实网络案例，帮助读者理解互联网的工作原理。是全球数百所大学采用的计算机网络教材。', '', 1, NOW(), NOW(), 0),
(20, '设计模式：可复用面向对象软件的基础', 'GoF', '9787111220275', 2, 79.00, 95, '机械工业出版社', '2004-01-01', '《设计模式》是面向对象设计的里程碑之作，系统总结了23种经典设计模式。每种模式都包含动机、结构、适用场景和代码示例。对于希望写出优雅、可扩展代码的开发者来说，这是一本必备的参考书。', '', 1, NOW(), NOW(), 0),
(21, 'Spring实战',        '克雷格·沃尔斯',   '9787115494619', 2, 99.00, 110, '人民邮电出版社',   '2019-01-01', '《Spring实战》是学习和使用Spring框架的权威指南。本书全面介绍了Spring的核心特性，包括依赖注入、面向切面编程、Spring MVC、Spring Boot、反应式编程、微服务等。通过大量实例帮助读者快速上手。', '', 1, NOW(), NOW(), 0),
(22, '鸟哥的Linux私房菜：基础学习篇', '鸟哥', '9787115358868', 2, 88.00, 130, '人民邮电出版社', '2014-07-01', '本书是Linux入门与进阶的经典之作，内容涵盖Linux的安装、文件系统、Shell与命令行、用户管理、进程管理、Shell脚本编程等。语言通俗易懂，幽默风趣，是学习Linux的最佳入门读物。', '', 1, NOW(), NOW(), 0),

-- ====================
-- 历史人文 (category_id = 3, 8本)
-- ====================
(23, '万历十五年',        '黄仁宇',    '9787108009821', 3, 36.00, 140, '生活·读书·新知三联书店', '1997-05-01', '《万历十五年》以1587年为切入点，通过几个关键历史人物——万历皇帝、申时行、张居正、海瑞、戚继光、李贽——的命运，揭示了中国传统社会管理存在的问题。视角独特，分析深刻，是了解中国明朝乃至整个中国历史的重要著作。', '', 1, NOW(), NOW(), 0),
(24, '人类简史',          '尤瓦尔·赫拉利', '9787508647357', 3, 68.00, 200, '中信出版社',       '2014-11-01', '《人类简史》从十万年前有生命迹象开始讲起，一直讲到21世纪。书中探讨了人类如何从动物界的一支普通物种跃升为地球主宰，以及金钱、帝国、宗教和科学革命如何塑造了人类世界。这是一部宏大的人类文明故事。', '', 1, NOW(), NOW(), 0),
(25, '全球通史',          '斯塔夫里阿诺斯', '9787301109489', 3, 128.00, 70, '北京大学出版社',   '2006-10-01', '《全球通史》将整个世界看作一个不可分割的有机整体，从全球视角审视各文明的互动与发展。摒弃了西方中心论，兼顾各地区的文明贡献，是了解世界历史的必读经典。', '', 1, NOW(), NOW(), 0),
(26, '枪炮、病菌与钢铁',  '贾雷德·戴蒙德', '9787532125685', 3, 55.00, 100, '上海译文出版社',   '2006-04-01', '为什么是欧亚大陆征服了美洲，而不是反过来？本书从地理、环境、生物等角度解释了各大洲人类社会不同发展路径的深层原因。戴蒙德以跨学科视野颠覆了传统种族主义的解释框架，是一部改变世界观的杰作。', '', 1, NOW(), NOW(), 0),
(27, '明朝那些事儿',      '当年明月',  '9787213045012', 3, 358.20, 60, '浙江人民出版社',   '2009-01-01', '《明朝那些事儿》以幽默风趣的语言讲述了明朝从建立到覆亡近三百年的历史。作者当年明月将严谨的史料与轻松的笔触结合，让历史变得生动有趣，开启了全民读史的热潮。套装共七册。', '', 1, NOW(), NOW(), 0),
(28, '丝绸之路：一部全新的世界史', '彼得·弗兰科潘', '9787308061454', 3, 128.00, 55, '浙江大学出版社', '2016-09-01', '本书以丝绸之路为主线，重新梳理了从古代到现代的世界史。作者指出，世界的中心从来不是欧洲和大西洋，而是连接东西方的中亚枢纽。两千年来，丝绸之路始终是文明交流、贸易往来和帝国争霸的核心地带。', '', 1, NOW(), NOW(), 0),
(29, '史记（中华经典普及文库）', '司马迁', '9787101051469', 3, 45.00, 90, '中华书局',         '2009-01-01', '《史记》是中国第一部纪传体通史，记载了从黄帝到汉武帝太初年间约三千年的历史。全书分本纪、表、书、世家、列传五部分，总计一百三十篇。司马迁以其卓越的史识和文采，为后世史学树立了不朽的典范。', '', 1, NOW(), NOW(), 0),
(30, '乡土中国',          '费孝通',    '9787100015271', 3, 20.00, 180, '商务印书馆',         '2011-12-01', '《乡土中国》是费孝通先生的经典之作，深入浅出地分析了中国乡土社会的结构特征。书中提出的"差序格局""熟人社会""礼治秩序"等概念，至今仍是我们理解中国社会文化的重要理论工具。', '', 1, NOW(), NOW(), 0),

-- ====================
-- 经济管理 (category_id = 4, 8本)
-- ====================
(31, '经济学原理：微观经济学分册', 'N·格里高利·曼昆', '9787301256909', 4, 89.00, 95, '北京大学出版社', '2015-05-01', '曼昆的《经济学原理》是全球最受欢迎的经济学入门教材。本书以通俗易懂的语言、丰富的案例，系统介绍了供求原理、市场效率、外部性、公共物品、企业行为等微观经济学的核心概念。', '', 1, NOW(), NOW(), 0),
(32, '思考，快与慢',      '丹尼尔·卡尼曼', '9787508633558', 4, 69.00, 115, '中信出版社',       '2012-07-01', '诺贝尔经济学奖得主丹尼尔·卡尼曼的集大成之作。书中将人类的思维模式分为"系统1"（快速直觉）和"系统2"（慢速理性），揭示了人类决策中的各种认知偏差，彻底改变了人们对思考方式的理解。', '', 1, NOW(), NOW(), 0),
(33, '国富论',            '亚当·斯密',  '9787100004879', 4, 68.00, 70,  '商务印书馆',         '2015-08-01', '《国富论》是现代经济学之父亚当·斯密的不朽经典，奠定了劳动分工、自由市场等经济学基本概念。书中系统阐述了国民财富的性质和原因，论证了"看不见的手"如何引导自利行为促进公共利益。', '', 1, NOW(), NOW(), 0),
(34, '从0到1：开启商业与未来的秘密', '彼得·蒂尔', '9787508651538', 4, 45.00, 160, '中信出版社', '2015-01-01', 'PayPal创始人彼得·蒂尔在本书中分享了他的创业哲学：真正的创新是从0到1的创造，而非从1到N的复制。书中探讨了垄断的价值、竞争的本质、创业中的迷思以及如何构建成功的商业模式。', '', 1, NOW(), NOW(), 0),
(35, '穷查理宝典：查理·芒格智慧箴言录', '彼得·考夫曼', '9787508663326', 4, 99.00, 75, '中信出版社', '2016-08-01', '收录了查理·芒格的演讲、文章和投资哲学。芒格提倡"多元思维模型"，用不同学科的知识框架来分析问题，避免单一视角的局限。全书充满了睿智的人生智慧和投资洞见。', '', 1, NOW(), NOW(), 0),
(36, '影响力',            '罗伯特·西奥迪尼', '9787559601155', 4, 55.00, 130, '北京联合出版公司', '2017-03-01', '《影响力》是社会心理学领域的经典著作，总结了说服他人的六大原则：互惠、承诺和一致、社会认同、喜好、权威、稀缺。理解这些原理，既能帮助你在商业谈判中占得先机，也能帮助你识破操纵，保护自己。', '', 1, NOW(), NOW(), 0),
(37, '卓有成效的管理者',  '彼得·德鲁克', '9787111398998', 4, 42.00, 105, '机械工业出版社',   '2012-08-01', '现代管理学之父德鲁克的代表作。本书指出，管理者的工作必须是卓有成效的，而卓有成效是可以学会的。德鲁克给出了时间管理、用人所长、要事优先、有效决策等五项习惯，帮助管理者提升效能。', '', 1, NOW(), NOW(), 0),
(38, '债务危机：我的应对原则', '瑞·达利欧', '9787521700077', 4, 98.00, 60, '中信出版社',     '2019-03-01', '桥水基金创始人瑞·达利欧在本书中深入剖析了债务危机的内在机制。他通过研究48次大型债务危机，总结出了一套"典型债务大周期"模型，为理解经济周期和预测金融危机提供了重要框架。', '', 1, NOW(), NOW(), 0),

-- ====================
-- 科学技术 (category_id = 5, 7本)
-- ====================
(39, '时间简史',          '史蒂芬·霍金', '9787535732309', 5, 45.00, 140, '湖南科学技术出版社', '2010-04-01', '《时间简史》是史蒂芬·霍金的传世经典。从宇宙大爆炸到黑洞，从量子力学到时间旅行，霍金以通俗的语言带领读者探索宇宙的起源和命运。本书被翻译成40多种语言，销量超过2500万册。', '', 1, NOW(), NOW(), 0),
(40, '上帝掷骰子吗？量子物理史话', '曹天元', '9787559630612', 5, 49.80, 120, '北京联合出版公司', '2019-07-01', '本书用轻松诙谐的笔调讲述了量子物理从诞生到发展的百年历程。从赫兹到普朗克，从爱因斯坦到玻尔，在这场震撼物理世界的大辩论中，一个个科学巨匠轮番登场，让读者领略量子力学的神奇与魅力。', '', 1, NOW(), NOW(), 0),
(41, '物种起源',          '查尔斯·达尔文', '9787100024136', 5, 39.00, 80,  '商务印书馆',       '1995-06-01', '《物种起源》是生物学史上的一座里程碑。达尔文在大量观察和实验的基础上，提出了"自然选择"为核心的进化理论，从根本上改变了人类对生命世界的认识。这本书至今仍是理解生物多样性的基础。', '', 1, NOW(), NOW(), 0),
(42, '宇宙',              '卡尔·萨根',  '9787202083725', 5, 68.00, 65,  '河北人民出版社',     '2017-03-01', '《宇宙》是卡尔·萨根的天文学科普经典，配合同名纪录片的播出引起了巨大反响。萨根以诗意的笔触，带领读者从地球出发，遨游银河系，探索宇宙深处的奥秘，思考人类在宇宙中的位置。', '', 1, NOW(), NOW(), 0),
(43, '自私的基因',        '理查德·道金斯', '9787508633954', 5, 68.00, 100, '中信出版社',       '2012-09-01', '道金斯在本书中提出了"基因的自私性"这一革命性观点：进化以基因为单位，生物个体不过是基因为了延续自身而创造的"生存机器"。这本书彻底更新了人们对进化论的理解，影响深远。', '', 1, NOW(), NOW(), 0),
(44, '机器学习',          '周志华',    '9787302423287', 5, 88.00, 115, '清华大学出版社',     '2016-01-01', '《机器学习》（俗称"西瓜书"）是华语界广受好评的机器学习入门教材。周志华教授以清晰严谨的语言，系统地介绍了机器学习的基本概念、经典算法和前沿进展，理论推导详实，适合初学者系统学习。', '', 1, NOW(), NOW(), 0),
(45, 'what if? 那些古怪又让人忧心的问题', '兰道尔·门罗', '9787550219847', 5, 49.80, 135, '北京联合出版公司', '2015-05-01', '如果所有雨水都汇聚成一滴大水珠会怎样？如果地球停止转动了会发生什么？前NASA机器人专家兰道尔·门罗用严谨的科学计算来回答这些荒诞不经的问题。结果既出人意料又妙趣横生，令人捧腹。', '', 1, NOW(), NOW(), 0),

-- ====================
-- 哲学心理 (category_id = 6, 5本)
-- ====================
(46, '苏菲的世界',        '乔斯坦·贾德', '9787506341271', 6, 38.00, 145, '作家出版社',         '2007-10-01', '《苏菲的世界》以小说形式讲述了西方哲学史。14岁的少女苏菲不断收到神秘来信，在一位神秘导师的引导下，她开始了从古希腊到20世纪的哲学探索之旅。这本书让枯燥的哲学变得妙趣横生，是公认的哲学入门经典。', '', 1, NOW(), NOW(), 0),
(47, '被讨厌的勇气：阿德勒心理学入门', '岸见一郎', '9787111495482', 6, 55.00, 180, '机械工业出版社', '2015-03-01', '本书以青年与哲人的对话形式，深入浅出地讲解了阿德勒心理学。书中提出了"课题分离""目的论"等颠覆传统观念的思想，告诉读者：真正的自由来自于不在意他人的评价，拥有被讨厌的勇气。', '', 1, NOW(), NOW(), 0),
(48, '理想国',            '柏拉图',    '9787100028561', 6, 40.00, 85,  '商务印书馆',         '1986-08-01', '《理想国》是古希腊哲学家柏拉图的代表作，也是西方哲学思想的源头之一。全书以对话体的形式，探讨了正义、教育、政体、灵魂不朽等根本问题，构想了哲学家统治的理想城邦。', '', 1, NOW(), NOW(), 0),
(49, '社会性动物',        '艾略特·阿伦森', '9787561794333', 6, 59.80, 100, '华东师范大学出版社', '2014-07-01', '《社会性动物》是社会心理学领域的经典教材，被誉为"美国社会心理学的圣经"。书中以大量生动有趣的实验案例，深入剖析了从众、说服、攻击、偏见、吸引等社会心理现象。阅读本书，你会更深刻地理解自己和他人的行为。', '', 1, NOW(), NOW(), 0),
(50, '中国哲学简史',      '冯友兰',    '9787301070925', 6, 38.00, 90,  '北京大学出版社',     '2013-01-01', '《中国哲学简史》是哲学大师冯友兰的代表作，用通俗流畅的语言系统梳理了从先秦诸子到近现代的中国哲学发展脉络。本书原本以英文写成，面向西方读者介绍中国哲学，出版后迅速成为西方了解中国思想的首选读物。', '', 1, NOW(), NOW(), 0);
